parameters.jsCode:
const base = (() => {
  try {
    return $item(0).$node['Session Bootstrap'].json ?? {};
  } catch {
    return {};
  }
})();
const payload = $json ?? {};
const event = base.event && typeof base.event === 'object' ? base.event : {};
const session = base.session && typeof base.session === 'object' ? base.session : {};
const client_config = base.client_config && typeof base.client_config === 'object' ? base.client_config : {};

const allowedMessageFunctions = ['info_request', 'refinement', 'negotiation', 'acknowledgment', 'clarification', 'fresh_request'];
const allowedBusinessIntents = ['store_info', 'product_search', 'pricing', 'exchange', 'support'];
const allowedTopics = ['store_info', 'product', 'exchange', 'pricing', 'location'];
const hardFallback = {
  message_function: 'clarification',
  business_intent: null,
  topic: null,
  confidence: 0.0,
  ambiguity: 1.0,
  missing_information: [],
  reference_resolution: {
    refers_to: null,
    resolved_id: null,
  },
  last_asked_key: null,
};

const issues = [];
const isRecord = (value) => !!value && typeof value === 'object' && !Array.isArray(value);
const parseJsonObject = (value) => {
  if (!value) return null;
  if (isRecord(value)) return value;
  if (typeof value !== 'string' || !value.trim()) return null;
  try {
    const parsed = JSON.parse(value);
    return isRecord(parsed) ? parsed : null;
  } catch {
    return null;
  }
};
const normalizeEnum = (value, allowed, label) => {
  if (typeof value !== 'string') {
    issues.push(label + '_type');
    return null;
  }
  const normalized = value.trim().toLowerCase();
  if (!allowed.includes(normalized)) {
    issues.push(label + '_invalid');
    return null;
  }
  return normalized;
};
const normalizeNullableEnum = (value, allowed, label) => {
  if (value === null || value === undefined) return null;
  return normalizeEnum(value, allowed, label);
};
const normalizeUnitNumber = (value, label) => {
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    issues.push(label + '_type');
    return null;
  }
  if (value < 0 || value > 1) {
    issues.push(label + '_range');
    return null;
  }
  return value;
};
const normalizeStringArray = (value, label) => {
  if (!Array.isArray(value)) {
    issues.push(label + '_type');
    return null;
  }
  const normalized = [];
  for (const item of value) {
    if (typeof item !== 'string') {
      issues.push(label + '_item_type');
      return null;
    }
    const text = item.trim();
    if (text) normalized.push(text);
  }
  return normalized;
};
const normalizeNullableString = (value, label) => {
  if (value === null || value === undefined) return null;
  if (typeof value !== 'string') {
    issues.push(label + '_type');
    return null;
  }
  const normalized = value.trim();
  return normalized || null;
};
const validateReferenceResolution = (value) => {
  if (!isRecord(value)) {
    issues.push('reference_resolution_type');
    return null;
  }
  return {
    refers_to: normalizeNullableString(value.refers_to, 'reference_resolution.refers_to'),
    resolved_id: normalizeNullableString(value.resolved_id, 'reference_resolution.resolved_id'),
  };
};

const rawResponse = parseJsonObject(payload.choices?.[0]?.message?.content)
  || parseJsonObject(payload.output_text)
  || parseJsonObject(payload.text)
  || parseJsonObject(payload.data)
  || parseJsonObject(payload.result)
  || parseJsonObject(payload);

const hasLegacyShape = isRecord(rawResponse) && (
  Object.prototype.hasOwnProperty.call(rawResponse, 'message_classification')
  || Object.prototype.hasOwnProperty.call(rawResponse, 'business_topic')
  || Object.prototype.hasOwnProperty.call(rawResponse, 'sentiment')
  || Object.prototype.hasOwnProperty.call(rawResponse, 'tone')
  || Object.prototype.hasOwnProperty.call(rawResponse, 'entities_detected')
);
const legacyText = (value) => typeof value === 'string' && value.trim() ? value.trim() : null;
const legacyArray = (value) => Array.isArray(value)
  ? value.filter((item) => typeof item === 'string' && item.trim()).map((item) => item.trim())
  : [];
const legacyTopic = legacyText(rawResponse?.business_topic);
const legacyClassification = legacyText(rawResponse?.message_classification);
const legacyConfidenceValue = Number(rawResponse?.confidence);
const legacyConfidence = Number.isFinite(legacyConfidenceValue) ? legacyConfidenceValue : 0;
const legacyEntities = isRecord(rawResponse?.entities_detected) ? rawResponse.entities_detected : {};
const legacyAmbiguousRefs = legacyArray(legacyEntities.ambiguous_references);
const legacyBusinessIntent = legacyTopic === 'info_request'
  ? 'store_info'
  : (legacyTopic === 'product_search'
      ? 'product_search'
      : (legacyTopic === 'pricing'
          ? 'pricing'
          : (legacyTopic === 'exchange'
              ? 'exchange'
              : (legacyTopic === 'support' ? 'support' : null))));
const legacyTopicNormalized = legacyTopic === 'info_request'
  ? 'store_info'
  : (legacyTopic === 'product_search'
      ? 'product'
      : (legacyTopic === 'pricing'
          ? 'pricing'
          : (legacyTopic === 'exchange'
              ? 'exchange'
              : null)));
const legacyMessageFunction = (legacyClassification === 'acknowledgment' || legacyClassification === 'small_talk')
  ? 'acknowledgment'
  : (legacyTopic === 'pricing'
      ? 'negotiation'
      : (legacyTopic === 'info_request'
          ? 'info_request'
          : (legacyTopic === 'exchange' || legacyTopic === 'product_search' || legacyTopic === 'support' || legacyClassification === 'business'
              ? 'fresh_request'
              : 'clarification')));

let understanding_output = hardFallback;
if (!rawResponse) {
  issues.push('understanding_response_not_parseable');
} else if (hasLegacyShape) {
  understanding_output = {
    message_function: legacyMessageFunction,
    business_intent: legacyBusinessIntent,
    topic: legacyTopicNormalized,
    confidence: legacyConfidence,
    ambiguity: legacyAmbiguousRefs.length > 0 ? Math.max(0.1, 1 - legacyConfidence) : Math.max(0, 1 - legacyConfidence),
    missing_information: [],
    reference_resolution: {
      refers_to: legacyAmbiguousRefs[0] ?? null,
      resolved_id: null,
    },
    last_asked_key: legacyText(rawResponse.last_asked_key),
    message_classification: legacyClassification ?? 'clarification',
    business_topic: legacyTopic,
    sentiment: legacyText(rawResponse.sentiment) ?? 'neutral',
    tone: legacyText(rawResponse.tone) ?? 'casual',
    entities_detected: {
      product_mentions: legacyArray(legacyEntities.product_mentions),
      price_mentions: legacyArray(legacyEntities.price_mentions),
      condition_mentions: legacyArray(legacyEntities.condition_mentions),
      ambiguous_references: legacyAmbiguousRefs,
    },
    extracted_need: legacyText(rawResponse.extracted_need),
    reasoning: legacyText(rawResponse.reasoning),
  };
} else {
  const validated = {
    message_function: normalizeEnum(rawResponse.message_function, allowedMessageFunctions, 'message_function'),
    business_intent: normalizeNullableEnum(rawResponse.business_intent, allowedBusinessIntents, 'business_intent'),
    topic: normalizeNullableEnum(rawResponse.topic, allowedTopics, 'topic'),
    confidence: normalizeUnitNumber(rawResponse.confidence, 'confidence'),
    ambiguity: normalizeUnitNumber(rawResponse.ambiguity, 'ambiguity'),
    missing_information: normalizeStringArray(rawResponse.missing_information, 'missing_information'),
    reference_resolution: validateReferenceResolution(rawResponse.reference_resolution),
    last_asked_key: normalizeNullableString(rawResponse.last_asked_key, 'last_asked_key'),
  };

  const validationFailed = [
    validated.message_function,
    validated.confidence,
    validated.ambiguity,
    validated.missing_information,
    validated.reference_resolution,
  ].some((value) => value === null) || issues.length > 0;

  if (!validationFailed) {
    understanding_output = {
      message_function: validated.message_function,
      business_intent: validated.business_intent,
      topic: validated.topic,
      confidence: validated.confidence,
      ambiguity: validated.ambiguity,
      missing_information: validated.missing_information,
      reference_resolution: validated.reference_resolution,
      last_asked_key: validated.last_asked_key,
    };
  }
}

const understanding_meta = {
  validator_mode: 'pure_schema_validator',
  schema_mode: 'minimal_guard_v2',
  valid: issues.length === 0,
  issues,
  raw_response: rawResponse,
  fallback_applied: issues.length > 0,
  timestamp: Date.now(),
};
console.log(JSON.stringify({
  node: 'Understanding JSON Guard - Pure Validator',
  valid: understanding_meta.valid,
  fallback_applied: understanding_meta.fallback_applied,
  issues: understanding_meta.issues,
  raw_response: rawResponse,
}));

return [{
  json: {
    event,
    session,
    client_config,
    understanding_output,
    understanding_meta,
  },
}];

const input = $json ?? {};
const event = input.event && typeof input.event === 'object' ? input.event : {};
const session = input.session && typeof input.session === 'object' ? input.session : {};
const client_config = input.client_config && typeof input.client_config === 'object' ? input.client_config : {};
const understanding_output = input.understanding_output && typeof input.understanding_output === 'object' ? input.understanding_output : {};
const understanding_meta = input.understanding_meta && typeof input.understanding_meta === 'object' ? input.understanding_meta : {};
const text = String(event.text ?? '').trim();
const ambiguousReferences = Array.isArray(understanding_output.entities_detected?.ambiguous_references)
  ? understanding_output.entities_detected.ambiguous_references.filter((item) => typeof item === 'string' && item.trim())
  : [];
const shownProductsRaw = Array.isArray(session.flow_context?.buy_flow?.shown_products)
  ? session.flow_context.buy_flow.shown_products
  : [];
const currentInterest = session.flow_context?.buy_flow?.current_interest ?? null;
const currentFlow = session.conversation_state?.current_flow ?? null;

const normalizeProduct = (value, index) => {
  if (value === null || value === undefined) return null;
  if (typeof value === 'string' || typeof value === 'number') return { id: String(value), name: null, price: null, raw: value, index };
  if (typeof value !== 'object') return null;
  const priceValue = value.price_etb ?? value.price ?? value.amount ?? null;
  return {
    id: String(value.id ?? value.product_id ?? value.sku ?? ('option_' + index)),
    name: [value.brand, value.model].filter(Boolean).join(' ').trim() || value.name || value.title || null,
    price: Number.isFinite(Number(priceValue)) ? Number(priceValue) : null,
    raw: value,
    index,
  };
};
const shownProducts = shownProductsRaw.map(normalizeProduct).filter(Boolean);

const resolveAmbiguousReference = () => {
  if (ambiguousReferences.length === 0) return { confidence: 0, resolved_reference: null, resolved_product_name: null, ambiguous_reference: null };
  const label = ambiguousReferences[0].toLowerCase();
  const byCheapest = [...shownProducts].filter((item) => item.price !== null).sort((a, b) => a.price - b.price)[0] ?? null;
  const byLast = shownProducts[shownProducts.length - 1] ?? normalizeProduct(currentInterest, shownProducts.length + 1);
  const byFirst = shownProducts[0] ?? null;
  let chosen = null;
  if (label.includes('cheaper') || label.includes('cheapest')) chosen = byCheapest;
  else if (label.includes('first')) chosen = byFirst;
  else if (label.includes('last')) chosen = byLast;
  else if (label.includes('that one') || label.includes('the one') || label.includes('this one') || label.includes('same one')) chosen = normalizeProduct(currentInterest, shownProducts.length + 2) ?? byLast;
  return { confidence: chosen ? 0.85 : 0.35, resolved_reference: chosen ? { id: chosen.id, raw: chosen.raw } : null, resolved_product_name: chosen?.name ?? null, ambiguous_reference: label };
};
const inferFlow = () => {
  const topic = understanding_output.business_topic ?? null;
  if (topic === 'exchange') return 'exchange';
  if (topic === 'info_request') return 'info';
  if (topic === 'support') return 'support';
  if (topic === 'product_search' || topic === 'pricing' || topic === 'stock_check') return 'buy';
  return null;
};

const referenceResolution = resolveAmbiguousReference();
const inferredFlow = inferFlow();
const productMentions = Array.isArray(understanding_output.entities_detected?.product_mentions)
  ? understanding_output.entities_detected.product_mentions.filter((item) => typeof item === 'string' && item.trim())
  : [];

let rules_output = {
  reply_mode: 'small_talk_redirect',
  should_call_resolver: false,
  resolver_input: { flow: null, product_context: null, missing_fields: [], resolved_reference: null, resolved_product_name: null },
  session_update: {
    last_topic: understanding_output.business_topic ?? understanding_output.message_classification ?? null,
    flow_stage: currentFlow,
    ambiguous_reference: referenceResolution.ambiguous_reference,
    resolved_ambiguity: Boolean(referenceResolution.resolved_reference),
  },
  confidence: typeof understanding_output.confidence === 'number' ? understanding_output.confidence : 0,
  reasoning: 'default_small_talk_redirect',
};

const classification = understanding_output.message_classification ?? 'small_talk';
const sentiment = understanding_output.sentiment ?? 'neutral';

if (event.event_type === 'start_reset') {
  rules_output = { ...rules_output, reply_mode: 'small_talk_redirect', should_call_resolver: false, reasoning: 'start_reset_welcome', session_update: { ...rules_output.session_update, last_topic: null, flow_stage: null, ambiguous_reference: null, resolved_ambiguity: false } };
} else if (event.event_type === 'deep_link_start') {
  rules_output = { ...rules_output, reply_mode: 'business_resolve', should_call_resolver: true, resolver_input: { flow: 'buy', product_context: text || null, missing_fields: [], resolved_reference: null, resolved_product_name: productMentions[0] ?? null }, session_update: { ...rules_output.session_update, last_topic: 'product_search', flow_stage: 'buy' }, reasoning: 'deep_link_start_business_entry' };
} else if (typeof understanding_output.confidence !== 'number' || understanding_output.confidence < 0.6) {
  rules_output = { ...rules_output, reply_mode: 'handoff_admin', should_call_resolver: false, reasoning: 'low_understanding_confidence' };
} else if (classification === 'acknowledgment') {
  rules_output = { ...rules_output, reply_mode: 'acknowledge_and_close', should_call_resolver: false, reasoning: 'acknowledgment_detected' };
} else if (classification === 'small_talk' || classification === 'off_topic') {
  const reply_mode = sentiment === 'frustrated' ? 'handoff_admin' : ((sentiment === 'playful' || understanding_output.tone === 'humorous') ? 'small_talk_redirect' : (classification === 'small_talk' ? 'small_talk_redirect' : 'off_topic_redirect'));
  rules_output = { ...rules_output, reply_mode, should_call_resolver: false, reasoning: classification + '_handled_without_resolver' };
} else if (classification === 'business') {
  const productContext = productMentions[0] ?? currentInterest ?? null;
  const missingFields = inferredFlow === 'buy' && !productContext && !referenceResolution.resolved_reference ? ['product_context'] : [];
  if (ambiguousReferences.length > 0) {
    if (referenceResolution.confidence >= 0.8) {
      rules_output = { ...rules_output, reply_mode: 'business_resolve', should_call_resolver: true, resolver_input: { flow: inferredFlow, product_context: productContext, missing_fields: missingFields, resolved_reference: referenceResolution.resolved_reference, resolved_product_name: referenceResolution.resolved_product_name }, session_update: { ...rules_output.session_update, flow_stage: inferredFlow, ambiguous_reference: referenceResolution.ambiguous_reference, resolved_ambiguity: true }, reasoning: 'ambiguous_reference_resolved_from_session' };
    } else {
      rules_output = { ...rules_output, reply_mode: 'clarify_reference', should_call_resolver: false, resolver_input: { ...rules_output.resolver_input, flow: inferredFlow, product_context: productContext }, session_update: { ...rules_output.session_update, flow_stage: inferredFlow, ambiguous_reference: referenceResolution.ambiguous_reference, resolved_ambiguity: false }, reasoning: 'ambiguous_reference_needs_clarification' };
    }
  } else if (inferredFlow && currentFlow && inferredFlow === currentFlow) {
    rules_output = { ...rules_output, reply_mode: 'resume_previous_flow', should_call_resolver: true, resolver_input: { flow: inferredFlow, product_context: productContext, missing_fields: missingFields, resolved_reference: null, resolved_product_name: productMentions[0] ?? null }, session_update: { ...rules_output.session_update, flow_stage: inferredFlow }, reasoning: 'continues_existing_flow' };
  } else {
    rules_output = { ...rules_output, reply_mode: 'business_resolve', should_call_resolver: true, resolver_input: { flow: inferredFlow, product_context: productContext, missing_fields: missingFields, resolved_reference: null, resolved_product_name: productMentions[0] ?? null }, session_update: { ...rules_output.session_update, flow_stage: inferredFlow }, reasoning: 'business_request_ready_for_resolver' };
  }
}

return [{ json: { event, session, client_config, understanding_output, understanding_meta, rules_output } }];

parameters.jsonBody:
={{ JSON.stringify((() => {
  const cleanPhoneType = (value) => {
    if (typeof value !== 'string') return null;
    const normalized = value
      .replace(/\b(32|64|128|256|512|1024)\s*gb\b/ig, ' ')
      .replace(/\b(iphone|samsung|pixel|redmi|xiaomi|tecno|infinix|oppo|vivo|realme|itel|nokia)(\d)/ig, '$1 $2')
      .replace(/\b(pro)(max)\b/ig, '$1 $2')
      .replace(/\s+/g, ' ')
      .trim();
    return normalized || null;
  };
  const extractFromText = (value) => {
